```python
import os
import json
import base64
import hashlib
import time
from typing import Optional
from fastapi import FastAPI, Request, Header, HTTPException
from pydantic import BaseModel
import requests
from dotenv import load_dotenv

load_dotenv()

# Config from environment
PHONEPE_CLIENT_ID = os.getenv("PHONEPE_CLIENT_ID")
PHONEPE_CLIENT_SECRET = os.getenv("PHONEPE_CLIENT_SECRET")
PHONEPE_MERCHANT_ID = os.getenv("PHONEPE_MERCHANT_ID")
PHONEPE_SALT_KEY = os.getenv("PHONEPE_SALT_KEY")
PHONEPE_SALT_INDEX = os.getenv("PHONEPE_SALT_INDEX")  # e.g., '1'
PHONEPE_ENV = os.getenv("PHONEPE_ENV", "SANDBOX")
WEBHOOK_USERNAME = os.getenv("PHONEPE_WEBHOOK_USERNAME")
WEBHOOK_PASSWORD = os.getenv("PHONEPE_WEBHOOK_PASSWORD")

# Endpoints (sandbox example)
BASE_SANDBOX = "https://api-preprod.phonepe.com/apis/pgsandbox"
BASE_PROD = "https://api.phonepe.com/apis/pg"
AUTH_SANDBOX = "https://api-preprod.phonepe.com/apis/identity-manager/v1/oauth/token"
AUTH_PROD = "https://api.phonepe.com/apis/identity-manager/v1/oauth/token"

AUTH_URL = AUTH_PROD if PHONEPE_ENV == "PRODUCTION" else AUTH_SANDBOX
BASE_URL = BASE_PROD if PHONEPE_ENV == "PRODUCTION" else BASE_SANDBOX

app = FastAPI()

# Simple token cache (for demo). In production, use proper token storage with expiry.
_cached_token = {"value": None, "expiry": 0}

def get_oauth_token():
    now = int(time.time())
    if _cached_token["value"] and _cached_token["expiry"] > now + 30:
        return _cached_token["value"]

    # Acquire token using client credentials
    resp = requests.post(
        AUTH_URL,
        json={
            "client_id": PHONEPE_CLIENT_ID,
            "client_secret": PHONEPE_CLIENT_SECRET,
            "grant_type": "client_credentials"
        },
        timeout=10
    )
    resp.raise_for_status()
    data = resp.json()
    token = data.get("access_token")
    expires_in = data.get("expires_in", 3600)
    _cached_token["value"] = token
    _cached_token["expiry"] = now + int(expires_in)
    return token

# X-VERIFY generation (per PhonePe docs: base64(payload) + apiPath + saltKey -> SHA256 -> UPPER HEX + '###' + saltIndex)

def generate_x_verify(api_path: str, payload_obj: dict) -> str:
    json_str = json.dumps(payload_obj, separators=(",", ":"))  # compact
    b64 = base64.b64encode(json_str.encode()).decode()
    to_hash = f"{b64}{api_path}{PHONEPE_SALT_KEY}"
    sha = hashlib.sha256(to_hash.encode()).hexdigest().upper()
    x_verify = f"{sha}###{PHONEPE_SALT_INDEX}"
    return x_verify

# Request models
class CreatePaymentRequest(BaseModel):
    merchantOrderId: str
    amount: int  # in paisa
    redirectUrl: str
    callbackUrl: Optional[str] = None

@app.post("/api/payment/initiate")
async def initiate_payment(req: CreatePaymentRequest):
    token = get_oauth_token()
    api_path = "/checkout/v2/pay"
    url = f"{BASE_URL}{api_path}"

    body = {
        "merchantId": PHONEPE_MERCHANT_ID,
        "merchantOrderId": req.merchantOrderId,
        "amount": req.amount,
        "redirectUrl": req.redirectUrl
    }
    if req.callbackUrl:
        body["callbackUrl"] = req.callbackUrl

    x_verify = generate_x_verify(api_path, body)

    headers = {
        "Content-Type": "application/json",
        "X-VERIFY": x_verify,
        "Authorization": f"O-Bearer {token}"
    }

    resp = requests.post(url, json=body, headers=headers, timeout=15)
    resp.raise_for_status()
    return resp.json()

@app.get("/api/payment/status/{merchantOrderId}")
async def payment_status(merchantOrderId: str):
    token = get_oauth_token()
    api_path = f"/checkout/v2/order/{merchantOrderId}/status"
    url = f"{BASE_URL}{api_path}"

    headers = {
        "Authorization": f"O-Bearer {token}"
    }
    resp = requests.get(url, headers=headers, timeout=10)
    resp.raise_for_status()
    return resp.json()

@app.post("/api/webhook")
async def phonepe_webhook(request: Request, authorization: Optional[str] = Header(None)):
    # PhonePe sends Basic auth as Authorization: Basic <base64(username:password)>
    if not authorization or not authorization.startswith("Basic "):
        raise HTTPException(status_code=401, detail="Missing webhook auth")

    # Validate username/password against your configured webhook creds
    import base64
    creds = base64.b64decode(authorization.split(" ")[1]).decode()
    username, password = creds.split(":", 1)

    if username != WEBHOOK_USERNAME or password != WEBHOOK_PASSWORD:
        raise HTTPException(status_code=401, detail="Invalid webhook credentials")

    body = await request.json()

    # Process event types (checkout.order.completed, checkout.order.failed, etc.)
    event = body.get("event")
    payload = body.get("payload")

    if event == "checkout.order.completed":
        # handle success: update order state in DB, fulfill, etc.
        pass
    elif event == "checkout.order.failed":
        # handle failure
        pass

    return {"status": "received"}

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)
```

Notes / explanation for backend code

- Token acquisition: the backend exchanges client_id/client_secret for an OAuth access token; store and reuse until expiry rather than fetching every call [PhonePe Auth API docs](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/api-integration-website).
- X-VERIFY: the algorithm used above follows PhonePe's documented method and must be applied exactly to the request body and API path for requests that require the header [Calculating X-VERIFY](https://developer.phonepe.com/switch/documentation/calculating-x-verify).
- Webhook validation: PhonePe uses Basic auth (Authorization header with base64 username:password); verify that header and process events [Webhook Handling | PhonePe](https://developer.phonepe.com/payment-gateway/mobile-app-integration/standard-checkout-mobile/webhook-handling).

Frontend (React web) — minimal integration pattern

- Approach: frontend requests the backend to create a payment order, backend returns a tokenUrl (hosted PayPage URL) or the response required for invoking the hosted PayPage, then frontend invokes the PhonePe checkout JS to open the iframe or redirect user to PayPage.

PhonePe hosted PayPage JS snippet (iframe mode)

Include this script in your checkout HTML per PhonePe docs:

```html
<script src="https://mercury.phonepe.com/web/bundle/checkout.js"></script>
<button id="phonepe-pay-btn">Pay with PhonePe</button>
<script>
  function callback(response) {
    if (response === 'USER_CANCEL') {
      console.log('Payment cancelled by user');
    } else if (response === 'CONCLUDED') {
      console.log('Payment concluded');
      // Optionally verify payment status via backend
    }
  }

  document.getElementById('phonepe-pay-btn').addEventListener('click', async () => {
    // Call your backend to create order and obtain tokenUrl
    const res = await fetch('/api/payment/initiate', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ merchantOrderId: 'order-123', amount: 10000, redirectUrl: window.location.href }) });
    const data = await res.json();
    const tokenUrl = data?.redirectUrl || data?.tokenUrl || data?.paymentUrl; // adapt to your backend response

    window.PhonePeCheckout.transact({ tokenUrl, callback, type: 'IFRAME' });
  });
</script>
```

(Official snippet and invocation docs) [Invoke iframe PayPage](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/api-reference/invoke-iframe-paypage).

React component example (calls backend and redirects)

```jsx
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useLocation } from 'react-router-dom';

function useQuery() {
  return new URLSearchParams(useLocation().search);
}

export default function PhonePePayment() {
  const [amount, setAmount] = useState(100); // rupees
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState(null);
  const query = useQuery();

  useEffect(() => {
    const txn = query.get('txnId');
    const st = query.get('status');
    if (txn && st) setStatus(st);
  }, [query]);

  const startPayment = async () => {
    setLoading(true);
    try {
      const resp = await axios.post('/api/payment/initiate', {
        merchantOrderId: `order-${Date.now()}`,
        amount: amount * 100,
        redirectUrl: `${window.location.origin}/payment-callback`
      });

      const tokenUrl = resp.data.redirectUrl || resp.data.paymentUrl || resp.data.tokenUrl;
      if (!tokenUrl) throw new Error('No payment URL from backend');

      // Use PhonePe Checkout JS if present (iframe mode), otherwise redirect
      if (window.PhonePeCheckout) {
        window.PhonePeCheckout.transact({ tokenUrl, callback: (r) => console.log('PhonePe callback', r), type: 'IFRAME' });
      } else {
        window.location.href = tokenUrl; // fallback redirect
      }
    } catch (err) {
      console.error(err);
      alert('Payment initiation failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <h3>PhonePe UPI Payment</h3>
      <label>
        Amount (₹):
        <input type="number" value={amount} onChange={(e) => setAmount(Number(e.target.value))} />
      </label>
      <button onClick={startPayment} disabled={loading}>{loading ? 'Processing...' : 'Pay with PhonePe'}</button>
      {status && <p>Payment status: {status}</p>}
    </div>
  );
}
```

Testing procedures (Sandbox)

- Use the PhonePe UAT sandbox host for all test requests: https://api-preprod.phonepe.com/apis/pgsandbox [UAT Sandbox | PhonePe](https://developer.phonepe.com/payment-gateway/uat-testing-go-live/uat-sandbox).

- PhonePe provides a Test App (Android package com.phonepe.simulator) to simulate UPI flows and choose Success/Failure/Pending outcomes during QR or intent flows [UAT Sandbox | PhonePe](https://developer.phonepe.com/payment-gateway/uat-testing-go-live/uat-sandbox).

- Test card data (for card flows) and OTPs (e.g., OTP 123456) are provided by PhonePe’s sandbox docs for simulating card/netbanking transactions [UAT Sandbox | PhonePe](https://developer.phonepe.com/payment-gateway/uat-testing-go-live/uat-sandbox).

- Test cases to run:
  - Create payment (expected: redirectUrl/tokenUrl returned). Verify frontend opens PayPage. [PayPage invocation docs](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/api-reference/invoke-iframe-paypage).
  - Complete payment in PhonePe Test App and verify webhook (checkout.order.completed) and/or poll order status endpoint return success [Webhook Handling | PhonePe](https://developer.phonepe.com/payment-gateway/mobile-app-integration/standard-checkout-mobile/webhook-handling).
  - Simulate user cancel and ensure your callback and order status reflect 'USER_CANCEL' or failure.
  - Attempt refund and refund status flows in sandbox to validate refund API integration.

Common pitfalls and mitigations

- Mixing sandbox and production credentials or endpoints causes 404/RESOURCE_NOT_FOUND errors; ensure environment-specific configuration [Troubleshooting | PhonePe](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/troubleshooting) and community reports [Stack Overflow migration issue](https://stackoverflow.com/questions/77207378/issues-in-migrating-to-live-mode-phonepe-payment-gateway).

- Incorrect X-VERIFY generation (wrong path, payload serialization, salt, or saltIndex) will lead to checksum validation failures; follow the exact sequence in the official X-VERIFY guide and test with the sandbox [Calculating X-VERIFY](https://developer.phonepe.com/switch/documentation/calculating-x-verify).

- CORS and browser-origin issues: do not call PhonePe server APIs directly from browser — always route through your backend which holds secrets and tokens [Troubleshooting | PhonePe](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/troubleshooting).

- Webhook misconfiguration: ensure the webhook URL is HTTPS, publicly reachable, configured on PhonePe merchant console, and set to accept POST JSON with Basic auth; always verify the Basic auth header on receipt [Webhook Handling | PhonePe](https://developer.phonepe.com/payment-gateway/mobile-app-integration/standard-checkout-mobile/webhook-handling).

- Domain/referrer mismatch: production flows require whitelisted domains and proper redirectUrl/callbackUrl values; do not use localhost in production and ensure redirect/callback domains match merchant configuration [Troubleshooting | PhonePe](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/troubleshooting).

- Token expiration handling: cache OAuth tokens until expiry and refresh proactively to avoid 401 Unauthorized errors during peak flows [PhonePe Auth docs](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/api-integration-website).

Operational checklist before going live

- Confirm merchant KYC and production credentials from PhonePe merchant portal [PhonePe Payment Gateway API Documentation](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/api-integration-website).
- Replace sandbox endpoints with production endpoints and update all credentials accordingly [UAT Sandbox | PhonePe](https://developer.phonepe.com/payment-gateway/uat-testing-go-live/uat-sandbox).
- Ensure X-VERIFY logic uses production salt key and salt index precisely [Calculating X-VERIFY](https://developer.phonepe.com/switch/documentation/calculating-x-verify).
- Configure and verify webhook endpoint with Basic auth credentials in PhonePe dashboard and test webhook deliveries in sandbox first [Webhook Handling | PhonePe](https://developer.phonepe.com/payment-gateway/mobile-app-integration/standard-checkout-mobile/webhook-handling).
- Run end-to-end sandbox test cases (success, failure, pending) using PhonePe Test App and test cards [UAT Sandbox | PhonePe](https://developer.phonepe.com/payment-gateway/uat-testing-go-live/uat-sandbox).

Useful PhonePe documentation links (referenced inline above)

- API & integration overview: https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/api-integration-website
- X-VERIFY calculation: https://developer.phonepe.com/switch/documentation/calculating-x-verify
- Invoke iframe PayPage snippet: https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/api-reference/invoke-iframe-paypage
- Sandbox / UAT testing: https://developer.phonepe.com/payment-gateway/uat-testing-go-live/uat-sandbox
- Webhook handling: https://developer.phonepe.com/payment-gateway/mobile-app-integration/standard-checkout-mobile/webhook-handling
- Backend Python SDK guidance: https://developer.phonepe.com/payment-gateway/backend-sdk/python-be-sdk/integration-steps
- Troubleshooting guidance: https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/troubleshooting

Testing checklist (short)

- Validate token endpoint returns access_token and expiry. [PhonePe Auth docs](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/api-integration-website)
- Validate initiate payment returns tokenUrl/redirectUrl. [PayPage invocation docs](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/api-reference/invoke-iframe-paypage)
- Complete payment in PhonePe Test App and confirm webhook event (checkout.order.completed) is received and verified. [Webhook handling](https://developer.phonepe.com/payment-gateway/mobile-app-integration/standard-checkout-mobile/webhook-handling)
- Use order status API to cross-check final state. [Order status endpoint](https://developer.phonepe.com/payment-gateway/website-integration/standard-checkout/api-integration/api-integration-website)
- Test failure and cancel scenarios; ensure your business logic handles rollbacks or retries gracefully.

Security reminders (short)

- Keep Client Secret / Salt Key offline in environment secrets (never commit to source control). Follow platform-specific secret management best practices (environment variables or secrets manager) [UAT Sandbox | PhonePe](https://developer.phonepe.com/payment-gateway/uat-testing-go-live/uat-sandbox).
- Use TLS for all endpoints and validate certificate chains.
- Log only non-sensitive metadata; never log the full payload containing secret values.

End of playbook checklist item: confirm that your backend uses the documented X-VERIFY algorithm, token handling, webhook Basic auth verification, and sandbox tests pass for success/failure/pending flows before switching to production endpoints [Calculating X-VERIFY](https://developer.phonepe.com/switch/documentation/calculating-x-verify) [Webhook Handling | PhonePe](https://developer.phonepe.com/payment-gateway/mobile-app-integration/standard-checkout-mobile/webhook-handling) [UAT Sandbox | PhonePe](https://developer.phonepe.com/payment-gateway/uat-testing-go-live/uat-sandbox).

