    resp = requests.post(
        AUTH_URL,
        json={
            "client_id": PHONEPE_CLIENT_ID,
            "client_secret": PHONEPE_CLIENT_SECRET,
            "grant_type": "client_credentials"
        },
        timeout=10
    )
    resp.raise_for_status()
    data = resp.json()
    token = data.get("access_token")
    expires_in = data.get("expires_in", 3600)
    _cached_token["value"] = token
    _cached_token["expiry"] = now + int(expires_in)
    return token

# X-VERIFY generation (per PhonePe docs: base64(payload) + apiPath + saltKey -> SHA256 -> UPPER HEX + '###' + saltIndex)

def generate_x_verify(api_path: str, payload_obj: dict) -> str:
    json_str = json.dumps(payload_obj, separators=(",", ":"))  # compact
    b64 = base64.b64encode(json_str.encode()).decode()
    to_hash = f"{b64}{api_path}{PHONEPE_SALT_KEY}"
    sha = hashlib.sha256(to_hash.encode()).hexdigest().upper()
    x_verify = f"{sha}###{PHONEPE_SALT_INDEX}"
    return x_verify

# Request models
class CreatePaymentRequest(BaseModel):
    merchantOrderId: str
    amount: int  # in paisa
    redirectUrl: str
    callbackUrl: Optional[str] = None

@app.post("/api/payment/initiate")
async def initiate_payment(req: CreatePaymentRequest):
    token = get_oauth_token()
    api_path = "/checkout/v2/pay"
    url = f"{BASE_URL}{api_path}"

    body = {
        "merchantId": PHONEPE_MERCHANT_ID,
        "merchantOrderId": req.merchantOrderId,
        "amount": req.amount,
        "redirectUrl": req.redirectUrl
    }
    if req.callbackUrl:
        body["callbackUrl"] = req.callbackUrl

    x_verify = generate_x_verify(api_path, body)

    headers = {
        "Content-Type": "application/json",
        "X-VERIFY": x_verify,
        "Authorization": f"O-Bearer {token}"
    }

    resp = requests.post(url, json=body, headers=headers, timeout=15)
    resp.raise_for_status()
    return resp.json()

@app.get("/api/payment/status/{merchantOrderId}")
async def payment_status(merchantOrderId: str):
    token = get_oauth_token()
    api_path = f"/checkout/v2/order/{merchantOrderId}/status"
    url = f"{BASE_URL}{api_path}"

    headers = {
        "Authorization": f"O-Bearer {token}"
    }
    resp = requests.get(url, headers=headers, timeout=10)
    resp.raise_for_status()
    return resp.json()

@app.post("/api/webhook")
async def phonepe_webhook(request: Request, authorization: Optional[str] = Header(None)):
    # PhonePe sends Basic auth as Authorization: Basic <base64(username:password)>
    if not authorization or not authorization.startswith("Basic "):
        raise HTTPException(status_code=401, detail="Missing webhook auth")

    # Validate username/password against your configured webhook creds
    import base64
    creds = base64.b64decode(authorization.split(" ")[1]).decode()
    username, password = creds.split(":", 1)

    if username != WEBHOOK_USERNAME or password != WEBHOOK_PASSWORD:
        raise HTTPException(status_code=401, detail="Invalid webhook credentials")

    body = await request.json()

    # Process event types (checkout.order.completed, checkout.order.failed, etc.)
    event = body.get("event")
    payload = body.get("payload")

